-- only use for the table has no positive numerical indices
function table.keysize(t)
    if (t == nil) then return 0 end
    local count = 0
    for k, v in pairs(t) do
        count = count + 1
    end
    return count
end

-- table == {} or nil
function table.isempty(t)
    if (t == nil) then
