-- tab ---> str
function table.tostring(t)
    if t == nil then return "" end
    local retstr= "{"

    local i = 1
    for key,value in pairs(t) do
        local signal = ","
        if i==1 then
            signal = ""
        end

        if key == i then
            retstr = retstr..signal..table._tostring_expand(value)
        else
            if type(key)=='number' or type(key) == 'string' then
                retstr = retstr..signal..'['..table._tostring_expand(key).."]="..table._tostring_expand(value)
            else
                if type(key)=='userdata' then
                    retstr = retstr..signal.."*s"..table.tostring(getmetatable(key)).."*e".."="..table._tostring_expand(value)
                else
                    retstr = retstr..signal..key.."="..table._tostring_expand(value)
                end
            end
        end

        i = i+1
    end

    retstr = retstr.."}"
    return retstr
end
-- str to tab
function table.string2table(str)
